document.addEventListener("click",e=>{const t=e.target;t.matches("[data-seeder]")&&(document.querySelectorAll("form").forEach(e=>{e.querySelectorAll("input, select, textarea").forEach(e=>{if(e instanceof HTMLInputElement)switch(e.type){case"email":e.value=`teste${Math.floor(1e3*Math.random())}@email.com`;break;case"number":e.value=String(Math.floor(9999*Math.random()));break;case"date":e.value=(new Date).toISOString().split("T")[0]??"";break;case"password":e.value="123456";break;case"checkbox":e.checked=Math.random()>.5;break;case"radio":if(!e.name)return;const t=document.querySelectorAll(`input[type="radio"][name="${e.name}"]`);if(t.length){const e=t[Math.floor(Math.random()*t.length)];e&&(e.checked=!0)}break;case"hidden":break;default:e.value=Math.random().toString(36).substring(2,10)}e instanceof HTMLSelectElement&&e.options.length>0&&(e.selectedIndex=0),e instanceof HTMLTextAreaElement&&(e.value=Math.random().toString(36).substring(2,20))})}),console.log("Formulários preenchidos.")),t.matches("[data-limpar]")&&(document.querySelectorAll("form").forEach(e=>{e.querySelectorAll("input, select, textarea").forEach(e=>{e instanceof HTMLInputElement&&("checkbox"===e.type||"radio"===e.type?e.checked=!1:e.value=""),e instanceof HTMLSelectElement&&e.options.length>0&&(e.selectedIndex=0),e instanceof HTMLTextAreaElement&&(e.value="")})}),console.log("Formulários limpos."))});
